std::vector<std::string> MeaningfulUpperTokens(const CstDocument& cst) {
  if (!cst.canonical_element_stream.elements.empty()) {
    std::vector<std::string> words;
    for (const auto& element : cst.canonical_element_stream.elements) {
      if (!element.canonical_text.empty()) {
        words.push_back(ToUpperAscii(element.canonical_text));
      } else {
        constexpr std::string_view prefix = "SBSQL.TOKEN.";
        if (element.canonical_id.rfind(prefix, 0) == 0) {
          words.push_back(element.canonical_id.substr(prefix.size()));
        } else {
          words.push_back(ToUpperAscii(element.canonical_id));
        }
      }
      if (words.back() == "STATEMENT_TERMINATOR") break;
    }
    return words;
  }
  std::vector<std::string> words;
  for (const auto& token : cst.tokens) {
    if (token.kind == TokenKind::kEnd) break;
    if (IsTriviaToken(token)) continue;
    words.push_back(ToUpperAscii(token.text));
  }
  return words;
}

bool IsParenthesizedCallInvocation(const CstDocument& cst) {
  const auto words = MeaningfulUpperTokens(cst);
  if (words.empty() || words.front() != "CALL") return false;
  for (std::size_t index = 1; index < words.size(); ++index) {
    if (words[index] == ";") break;
    if (words[index] == "(") return true;
  }
  return false;
}

bool IsIdentifierLikeToken(const Token& token) {
  return token.kind == TokenKind::kIdentifier || token.kind == TokenKind::kKeyword;
}

void AppendAliasSyntaxSurfaceIds(const Token& token, std::vector<std::string>* surface_ids) {
  if (surface_ids == nullptr) return;
  AppendIfMissing(surface_ids, "SBSQL-A71BB92503D1");
  AppendIfMissing(surface_ids, "SBSQL-8FCBFAE9BB6E");
  if (token.quoted) {
    AppendIfMissing(surface_ids, "SBSQL-52966F033E44");
    AppendIfMissing(surface_ids, "SBSQL-F2EFBBE3E8CF");
  } else if (token.kind == TokenKind::kKeyword) {
    AppendIfMissing(surface_ids, "SBSQL-16C870E47238");
  } else {
    AppendIfMissing(surface_ids, "SBSQL-12D6A4C483F0");
  }
}

bool ConsumeQualifiedName(const CstDocument& cst, std::size_t* index, std::size_t* part_count) {
  std::size_t parts = 0;
  bool expect_part = true;
  for (; *index < cst.tokens.size(); ++(*index)) {
    const auto& token = cst.tokens[*index];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) break;
    if (IsTriviaToken(token)) continue;
    if (expect_part) {
      if (!IsIdentifierLikeToken(token)) break;
      ++parts;
      expect_part = false;
      continue;
    }
    if (token.text == ".") {
      expect_part = true;
      continue;
    }
    break;
  }
  if (parts == 0 || expect_part) return false;
  *part_count = parts;
  return true;
}

bool ConsumeQualifiedNameWithLeaf(const CstDocument& cst,
                                  std::size_t* index,
                                  std::size_t* part_count,
                                  std::string* leaf) {
  std::size_t parts = 0;
  bool expect_part = true;
  std::string last_leaf;
  for (; *index < cst.tokens.size(); ++(*index)) {
    const auto& token = cst.tokens[*index];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) break;
    if (IsTriviaToken(token)) continue;
    if (expect_part) {
      if (!IsIdentifierLikeToken(token)) break;
      ++parts;
      last_leaf = token.text;
      expect_part = false;
      continue;
    }
    if (token.text == ".") {
      expect_part = true;
      continue;
    }
    break;
  }
  if (parts == 0 || expect_part) return false;
  *part_count = parts;
  if (leaf != nullptr) *leaf = std::move(last_leaf);
  return true;
}

bool ConsumeQualifiedNameWithParts(const CstDocument& cst,
                                   std::size_t* index,
                                   std::vector<std::string>* parts) {
  if (parts == nullptr) return false;
  std::vector<std::string> consumed;
  bool expect_part = true;
  for (; *index < cst.tokens.size(); ++(*index)) {
    const auto& token = cst.tokens[*index];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) break;
    if (IsTriviaToken(token)) continue;
    if (expect_part) {
      if (!IsIdentifierLikeToken(token)) break;
      consumed.push_back(token.text);
      expect_part = false;
      continue;
    }
    if (token.text == ".") {
      expect_part = true;
      continue;
    }
    break;
  }
  if (consumed.empty() || expect_part) return false;
  *parts = std::move(consumed);
  return true;
}

bool ConsumeKeyword(const CstDocument& cst, std::size_t* index, std::string_view keyword) {
  const auto expected = ToUpperAscii(keyword);
  for (; *index < cst.tokens.size(); ++(*index)) {
    const auto& token = cst.tokens[*index];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) return false;
    if (IsTriviaToken(token)) continue;
    if (ToUpperAscii(token.text) != expected) return false;
    ++(*index);
    return true;
  }
  return false;
}

bool PeekKeyword(const CstDocument& cst, std::size_t index, std::string_view keyword) {
  const auto expected = ToUpperAscii(keyword);
  for (; index < cst.tokens.size(); ++index) {
    const auto& token = cst.tokens[index];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) return false;
    if (IsTriviaToken(token)) continue;
    return ToUpperAscii(token.text) == expected;
  }
  return false;
}

std::string ConsumeIdentifierText(const CstDocument& cst, std::size_t* index) {
  for (; *index < cst.tokens.size(); ++(*index)) {
    const auto& token = cst.tokens[*index];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) return {};
    if (IsTriviaToken(token)) continue;
    if (!IsIdentifierLikeToken(token)) return {};
    ++(*index);
    return token.text;
  }
  return {};
}

std::string LowerAscii(std::string value) {
  for (char& ch : value) {
    if (ch >= 'A' && ch <= 'Z') ch = static_cast<char>(ch - 'A' + 'a');
  }
  return value;
}

bool OnlyStatementTerminatorRemains(const CstDocument& cst, std::size_t index) {
  for (; index < cst.tokens.size(); ++index) {
    const auto& token = cst.tokens[index];
    if (token.kind == TokenKind::kEnd) return true;
    if (IsTriviaToken(token)) continue;
    if (token.kind == TokenKind::kStatementTerminator) {
      for (++index; index < cst.tokens.size(); ++index) {
        if (cst.tokens[index].kind == TokenKind::kEnd) return true;
        if (!IsTriviaToken(cst.tokens[index])) return false;
      }
      return true;
    }
    return false;
  }
  return true;
}

std::string ConsumeSinglePrivilege(const CstDocument& cst, std::size_t* index) {
  for (; *index < cst.tokens.size(); ++(*index)) {
    const auto& token = cst.tokens[*index];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) return {};
    if (IsTriviaToken(token)) continue;
    if (!IsIdentifierLikeToken(token)) return {};
    const std::string privilege = ToUpperAscii(token.text);
    ++(*index);
    return privilege;
  }
  return {};
}

std::string ConsumeOptionalObjectKind(const CstDocument& cst, std::size_t* index) {
  static constexpr std::string_view kObjectKinds[] = {
      "DATABASE", "SCHEMA", "TABLE", "VIEW", "SEQUENCE", "DOMAIN",
      "PROCEDURE", "FUNCTION", "PACKAGE", "INDEX"};
  for (std::size_t probe = *index; probe < cst.tokens.size(); ++probe) {
    const auto& token = cst.tokens[probe];
    if (token.kind == TokenKind::kEnd || token.kind == TokenKind::kStatementTerminator) return "object";
    if (IsTriviaToken(token)) continue;
    const std::string upper = ToUpperAscii(token.text);
    for (const auto kind : kObjectKinds) {
      if (upper == kind) {
        *index = probe + 1;
        return LowerAscii(std::string(kind));
      }
    }
    return "object";
  }
  return "object";
}

bool ContainsWord(const std::vector<std::string>& words, std::string_view wanted) {
  for (const auto& word : words) {
    if (std::string_view(word) == wanted) return true;
  }
  return false;
}

bool StartsWithWords(const std::vector<std::string>& words,
                     std::initializer_list<std::string_view> prefix) {
  if (words.size() < prefix.size()) return false;
  std::size_t index = 0;
  for (const auto expected : prefix) {
    if (std::string_view(words[index]) != expected) return false;
    ++index;
  }
  return true;
}

bool ContainsTopLevelKeyword(const std::vector<const Token*>& tokens, std::string_view keyword) {
  const auto wanted = ToUpperAscii(keyword);
  int depth = 0;
  for (std::size_t index = 0; index < tokens.size(); ++index) {
    const auto* token = tokens[index];
    if (token == nullptr) continue;
    if (token->text == "(") {
      ++depth;
      continue;
    }
    if (token->text == ")") {
      if (depth > 0) --depth;
      continue;
    }
    if (depth == 0 && ToUpperAscii(token->text) == wanted) {
      if (wanted == "FROM" && index >= 2 &&
          ToUpperAscii(tokens[index - 1]->text) == "DISTINCT" &&
          ToUpperAscii(tokens[index - 2]->text) == "IS") {
        continue;
      }
      return true;
    }
  }
  return false;
}

bool OnlyOptionalTerminatorAfter(const std::vector<std::string>& words, std::size_t index) {
  return words.size() == index || (words.size() == index + 1 && words[index] == ";");
}

