Sbsfc077NonGeneralResidualRouteInfo MakeCompileStatementRoute(
    const std::vector<std::string>& words) {
  if (!StartsWithWords(words, {"COMPILE", "STATEMENT"})) return {};

  std::size_t end = words.size();
  if (end > 0 && words[end - 1] == ";") --end;
  if (end != 6 && end != 8) return {};
  if (words[2].empty() || words[3] != "AS" || words[4] != "SBLR" ||
      words[5].empty()) {
    return {};
  }

  std::string mode = "jit";
  if (end == 8) {
    if (words[6] != "MODE" || (words[7] != "JIT" && words[7] != "AOT")) {
      return {};
    }
    mode = LowerAscii(words[7]);
  }

  auto info = MakeSbsfc077Route("SBSQL-1DFEDF33C807",
                                "llvm_stmt",
                                "sblr.acceleration.llvm.v3",
                                "extensibility.compile_llvm_module",
                                AccelerationOpcodeForOperation("extensibility.compile_llvm_module"),
                                "EngineCompileLlvmModule",
                                "compile_statement_sblr",
                                "authority.engine.llvm_compile_api_required",
                                "llvm_compile_runtime",
                                "interpreter");
  info.compile_statement_name = LowerAscii(words[2]);
  info.compile_module_symbol = LowerAscii(words[5]);
  info.compile_mode = std::move(mode);
  return info;
}

