  const auto words = MeaningfulUpperTokens(cst);
  if (words.empty()) return {};

  if (StartsWithWords(words, {"EVENT", "TRIGGER", "FILTER"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-0125E8D0A6D1", "event_trigger_filter");
  if (StartsWithWords(words, {"AGGREGATE", "ATTR"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-03702B1136AD", "aggregate_attr");
  if (StartsWithWords(words, {"OP", "CLASS", "REF"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-04B9187EAD75", "op_class_ref");
