  if (StartsWithWords(words, {"LETTER"})) return MakeSbsfc081ExpressionDescriptorRoute("SBSQL-082DAD9A42A9", "letter");
  if (StartsWithWords(words, {"EXP", "PART"})) return MakeSbsfc081ExpressionDescriptorRoute("SBSQL-0935AF9FA568", "exp_part");
