  if (StartsWithWords(words, {"POSTFIX", "OP"})) return MakeSbsfc081ExpressionDescriptorRoute("SBSQL-11832617333F", "postfix_op");
  if (StartsWithWords(words, {"FORK", "STMT"})) return MakeSbsfc081QueryDescriptorRoute("SBSQL-13E1A83F7DD9", "fork_stmt");
  if (StartsWithWords(words, {"ACTION", "DESTINATION"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-1670155F0C42", "action_destination");
