  if (StartsWithWords(words, {"DIAG", "FIELD"})) return MakeSbsfc081ExpressionDescriptorRoute("SBSQL-3A85B0A04312", "diag_field");
  if (StartsWithWords(words, {"LANG", "NAME"})) return MakeSbsfc081ExpressionDescriptorRoute("SBSQL-3B1681CCCB3A", "lang_name");
  if (StartsWithWords(words, {"PATH", "SEGMENT"})) return MakeSbsfc081ExpressionDescriptorRoute("SBSQL-3B27132FBBCD", "path_segment");
  if (StartsWithWords(words, {"EXCLUSION", "ELEMENT"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-3E788869BFCD", "exclusion_element");
  if (StartsWithWords(words, {"HINT", "LIST"})) return MakeSbsfc081QueryDescriptorRoute("SBSQL-411811D60025", "hint_list");
  if (StartsWithWords(words, {"SUBPARTITION", "SPEC"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-43D4215C83C4", "subpartition_spec");
  if (StartsWithWords(words, {"OS", "FIELD", "MAPPING"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-4D9BF2CA1E65", "os_field_mapping");
  if (StartsWithWords(words, {"REVISION", "SPEC"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-4DBC46FD3C16", "revision_spec");
  if (StartsWithWords(words, {"OCCURRENCES", "REGEX", "FORM"})) return MakeSbsfc081ExpressionDescriptorRoute("SBSQL-4E6A112CC36E", "occurrences_regex_form");
  if (StartsWithWords(words, {"OPERATOR", "NAME"})) return MakeSbsfc081DdlDescriptorRoute("SBSQL-4EC678B20CF4", "operator_name");
  return {};
