bool BuildConcatExpressionProjectionItem(std::vector<ScalarProjectionItem> arguments,
                                         ScalarProjectionItem* item) {
  if (arguments.size() < 2 ||
      !NativeNowExpressionSurface("sb.scalar.concat") ||
      !NativeNowExpressionSurface("sb.operator.concat")) {
    return false;
  }
  for (const auto& argument : arguments) {
    if (argument.expression_kind != "literal" || argument.type_name != "text") {
      return false;
    }
  }
  item->expression_kind = "function";
  item->function_id = "sb.scalar.concat";
  item->type_name = "character";
  item->is_null = false;
  item->arguments = std::move(arguments);
  return true;
}

bool ParseConcatExpressionProjectionItem(const std::vector<const Token*>& tokens,
                                         std::size_t* index,
                                         ScalarProjectionItem* item) {
  std::size_t cursor = *index;
  ScalarProjectionItem first;
  if (!ParseScalarLiteralProjectionItem(tokens, &cursor, &first)) return false;

  std::vector<ScalarProjectionItem> arguments;
  arguments.push_back(std::move(first));
  bool saw_concat = false;
  while (cursor < tokens.size() && tokens[cursor]->text == "||") {
    saw_concat = true;
    ++cursor;
    ScalarProjectionItem next;
    if (!ParseScalarLiteralProjectionItem(tokens, &cursor, &next)) return false;
    arguments.push_back(std::move(next));
  }
  if (!saw_concat) return false;
  if (!BuildConcatExpressionProjectionItem(std::move(arguments), item)) return false;
  *index = cursor;
  return true;
}

bool BuildLikeProjectionItem(ScalarProjectionItem left,
                             ScalarProjectionItem right,
                             ScalarProjectionItem* item,
                             bool case_insensitive = false) {
  const std::string_view surface_name = case_insensitive ? "ILIKE" : "LIKE";
  if (!NativeNowExpressionSurface(surface_name)) {
    return false;
  }
  if (!case_insensitive && !NativeNowExpressionSurface("sb.operator.like")) return false;
  item->expression_kind = "operator";
  item->operator_id = case_insensitive ? "op_ilike" : "op_like";
  item->canonical_operator_id = case_insensitive ? "sb.operator.ilike" : "sb.operator.like";
  item->type_name = "boolean";
  item->is_null = false;
  item->arguments = {std::move(left), std::move(right)};
  return true;
}

std::optional<std::string> NormalizeLikePatternEscape(std::string_view pattern,
                                                      char escape_char) {
  std::string normalized;
  normalized.reserve(pattern.size());
  for (std::size_t index = 0; index < pattern.size(); ++index) {
    const char ch = pattern[index];
    if (ch == escape_char) {
      if (index + 1 >= pattern.size()) return std::nullopt;
      normalized.push_back('\\');
      normalized.push_back(pattern[++index]);
      continue;
    }
    if (escape_char != '\\' && ch == '\\') {
      normalized.push_back('\\');
      normalized.push_back('\\');
      continue;
    }
    normalized.push_back(ch);
  }
  return normalized;
}

