bool ParseSearchedCaseProjectionItem(const std::vector<const Token*>& tokens,
                                     std::size_t* index,
                                     ScalarProjectionItem* item) {
  std::size_t cursor = *index;
  if (!ConsumeTokenText(tokens, &cursor, "CASE")) return false;

  std::vector<ScalarProjectionItem> arguments;
  std::string result_type_name;
  bool saw_when = false;
  while (TokenTextEquals(tokens, cursor, "WHEN")) {
    saw_when = true;
    ++cursor;
    ScalarProjectionItem condition;
    if (!ParseCaseConditionProjectionItem(tokens, &cursor, &condition)) return false;
    if (!ConsumeTokenText(tokens, &cursor, "THEN")) return false;
    ScalarProjectionItem result;
    if (!ParseCaseValueProjectionItem(tokens, &cursor, &result)) return false;
    if (result_type_name.empty()) {
      result_type_name = result.type_name;
    } else if (result.type_name != result_type_name) {
      return false;
    }
    arguments.push_back(std::move(condition));
    arguments.push_back(std::move(result));
  }
  if (!saw_when || !ConsumeTokenText(tokens, &cursor, "ELSE")) return false;
  ScalarProjectionItem fallback;
  if (!ParseCaseValueProjectionItem(tokens, &cursor, &fallback)) return false;
  if (result_type_name.empty() || fallback.type_name != result_type_name) return false;
  if (!ConsumeTokenText(tokens, &cursor, "END")) return false;
  arguments.push_back(std::move(fallback));

  if (!BuildSearchedCaseProjectionItem(std::move(arguments), std::move(result_type_name), item)) {
    return false;
  }
  *index = cursor;
  return true;
}

bool ParseSimpleCaseProjectionItem(const std::vector<const Token*>& tokens,
                                   std::size_t* index,
                                   ScalarProjectionItem* item) {
  std::size_t cursor = *index;
  if (!ConsumeTokenText(tokens, &cursor, "CASE")) return false;
  ScalarProjectionItem case_operand;
  if (!ParseCaseValueProjectionItem(tokens, &cursor, &case_operand)) return false;

  std::vector<ScalarProjectionItem> arguments;
  std::string result_type_name;
  bool saw_when = false;
  while (TokenTextEquals(tokens, cursor, "WHEN")) {
    saw_when = true;
    ++cursor;
    ScalarProjectionItem when_operand;
    if (!ParseCaseValueProjectionItem(tokens, &cursor, &when_operand)) return false;
    if (!ConsumeTokenText(tokens, &cursor, "THEN")) return false;
    ScalarProjectionItem result;
    if (!ParseCaseValueProjectionItem(tokens, &cursor, &result)) return false;
    if (result_type_name.empty()) {
      result_type_name = result.type_name;
    } else if (result.type_name != result_type_name) {
      return false;
    }

    ScalarProjectionItem condition;
    if (!BuildBinaryOperatorProjectionItem("sb.operator.equal",
                                           "op_eq",
                                           "sb.operator.equal",
                                           case_operand,
                                           std::move(when_operand),
                                           &condition)) {
      return false;
    }
    arguments.push_back(std::move(condition));
    arguments.push_back(std::move(result));
  }
  if (!saw_when || !ConsumeTokenText(tokens, &cursor, "ELSE")) return false;
  ScalarProjectionItem fallback;
  if (!ParseCaseValueProjectionItem(tokens, &cursor, &fallback)) return false;
  if (result_type_name.empty() || fallback.type_name != result_type_name) return false;
  if (!ConsumeTokenText(tokens, &cursor, "END")) return false;
  arguments.push_back(std::move(fallback));

  if (!BuildSimpleCaseProjectionItem(std::move(arguments), std::move(result_type_name), item)) {
    return false;
  }
  *index = cursor;
  return true;
}

