std::optional<ParsedFunctionName> ParseFunctionNameTokenSequence(
    const std::vector<const Token*>& tokens,
    std::size_t index) {
  if (index >= tokens.size() || !IsIdentifierLikeToken(*tokens[index])) return std::nullopt;

  ParsedFunctionName parsed;
  parsed.text = tokens[index]->text;
  std::size_t cursor = index + 1;
  while (cursor + 1 < tokens.size() && tokens[cursor]->text == "." &&
         (IsIdentifierLikeToken(*tokens[cursor + 1]) ||
          tokens[cursor + 1]->kind == TokenKind::kNullLiteral)) {
    parsed.text += ".";
    parsed.text += tokens[cursor + 1]->text;
    cursor += 2;
  }
  parsed.end_index = cursor;
  return parsed;
}

bool ParseScalarOperatorFunctionProjectionItem(const std::vector<const Token*>& tokens,
                                               std::size_t* index,
                                               ScalarProjectionItem* item) {
  const auto parsed_name = ParseFunctionNameTokenSequence(tokens, *index);
  if (!parsed_name) return false;
  const auto descriptor = CanonicalOperatorForScalarProjection(parsed_name->text);
  if (!descriptor) return false;

  std::size_t cursor = parsed_name->end_index;
  if (cursor >= tokens.size() || tokens[cursor]->text != "(") return false;
  ++cursor;

  std::vector<ScalarProjectionItem> arguments;
  if (cursor < tokens.size() && tokens[cursor]->text == ")") {
    ++cursor;
  } else {
    while (cursor < tokens.size()) {
      ScalarProjectionItem argument;
      if (!ParseScalarLiteralProjectionItem(tokens, &cursor, &argument)) return false;
      arguments.push_back(std::move(argument));
      if (cursor >= tokens.size()) return false;
      if (tokens[cursor]->text == ",") {
        ++cursor;
        continue;
      }
      if (tokens[cursor]->text == ")") {
        ++cursor;
        break;
      }
      return false;
    }
  }

  if (!BuildOperatorProjectionItem(*descriptor, std::move(arguments), item)) return false;
  *index = cursor;
  return true;
}

bool ParseTimeSeriesWindowProjectionItem(const std::vector<const Token*>& tokens,
                                         std::size_t* index,
                                         ScalarProjectionItem* item) {
  const auto parsed_name = ParseFunctionNameTokenSequence(tokens, *index);
  if (!parsed_name) return false;
  const std::string lowered_name = LowerAscii(parsed_name->text);
  if (lowered_name != "timeseries.aggregate" &&
      lowered_name != "sb.fn.timeseries.aggregate") {
    return false;
  }

  std::size_t cursor = parsed_name->end_index;
  if (cursor >= tokens.size() || tokens[cursor]->text != "(") return false;
  ++cursor;

  std::vector<ScalarProjectionItem> arguments;
  while (cursor < tokens.size()) {
    ScalarProjectionItem argument;
    if (!ParseScalarLiteralProjectionItem(tokens, &cursor, &argument)) return false;
    arguments.push_back(std::move(argument));
    if (cursor >= tokens.size()) return false;
    if (tokens[cursor]->text == ",") {
      ++cursor;
      continue;
    }
    if (tokens[cursor]->text == ")") {
      ++cursor;
      break;
    }
    return false;
  }
  if (cursor >= tokens.size() || !TokenTextEquals(tokens, cursor, "WITHIN")) {
    return false;
  }
  ++cursor;
  ScalarProjectionItem interval;
  if (!ParseScalarLiteralProjectionItem(tokens, &cursor, &interval) ||
      interval.type_name != "interval") {
    return false;
  }
  if (!NativeNowExpressionSurfaceIds({"SBSQL-0C21F22A9420", "SBSQL-17B72695FA1A"})) {
    return false;
  }

  item->expression_kind = "function";
  item->function_id = "timeseries.aggregate";
  item->type_name = "real64";
  item->arguments = std::move(arguments);
  item->time_series_window_expr = true;
  item->time_series_window_interval_type = interval.type_name;
  item->time_series_window_interval_value = interval.value;
  item->time_series_window_interval_unit = interval.interval_unit;
  AppendSurfaceIds(&item->expression_surface_ids,
                   {"SBSQL-17B72695FA1A", "SBSQL-0C21F22A9420"});
  AppendIfMissing(&item->syntax_surface_ids, "SBSQL-0C21F22A9420");
  *index = cursor;
  return true;
}

std::optional<std::string> WindowFunctionNameForRoute(std::string_view function_name) {
  std::string lowered = LowerAscii(std::string(function_name));
  constexpr std::string_view kWindowPrefix = "sb.window.";
  if (lowered.starts_with(kWindowPrefix)) {
    lowered = lowered.substr(kWindowPrefix.size());
    if (lowered.empty() || lowered.find('.') != std::string::npos) return std::nullopt;
  }
  if (lowered == "row_number" || lowered == "rank" || lowered == "dense_rank" ||
      lowered == "percent_rank" || lowered == "cume_dist" || lowered == "ntile" ||
      lowered == "nth_value" || lowered == "lag" || lowered == "lead" ||
      lowered == "first_value" || lowered == "last_value") {
    return lowered;
  }
  return std::nullopt;
}

