bool ParseListAggOverflowClause(const std::vector<const Token*>& tokens,
                                std::size_t* index,
                                GroupByAggregateInfo* info) {
  if (index == nullptr || info == nullptr || !TokenTextEquals(tokens, *index, "ON")) return true;
  ++(*index);
  if (!ConsumeTokenText(tokens, index, "OVERFLOW")) {
    info->invalid_reason = "listagg_overflow_clause_requires_overflow_keyword";
    return false;
  }
  if (ConsumeTokenText(tokens, index, "ERROR")) {
    info->listagg_overflow_mode = "error";
    return true;
  }
  if (!ConsumeTokenText(tokens, index, "TRUNCATE")) {
    info->invalid_reason = "listagg_overflow_clause_requires_error_or_truncate";
    return false;
  }
  info->listagg_overflow_mode = "truncate";
  if (*index < tokens.size() && tokens[*index]->kind == TokenKind::kStringLiteral) {
    info->listagg_truncation_indicator = tokens[*index]->text;
    ++(*index);
  }
  if (ConsumeTokenText(tokens, index, "WITHOUT")) {
    if (!ConsumeTokenText(tokens, index, "COUNT")) {
      info->invalid_reason = "listagg_overflow_without_requires_count";
      return false;
    }
    info->listagg_with_count = "false";
  } else if (ConsumeTokenText(tokens, index, "WITH")) {
    if (!ConsumeTokenText(tokens, index, "COUNT")) {
      info->invalid_reason = "listagg_overflow_with_requires_count";
      return false;
    }
    info->listagg_with_count = "true";
  } else {
    info->listagg_with_count = "true";
  }
  return true;
}

