bool ParseTrimSpecialProjectionItem(const std::vector<const Token*>& tokens,
                                    std::size_t* index,
                                    ScalarProjectionItem* item) {
  if (index == nullptr || item == nullptr || !TokenTextEquals(tokens, *index, "TRIM")) return false;
  std::size_t cursor = *index + 1;
  if (!ConsumeTokenText(tokens, &cursor, "(")) return false;

  std::string function_id = "sb.special.trim_keyword";
  if (TokenTextEquals(tokens, cursor, "LEADING") ||
      TokenTextEquals(tokens, cursor, "TRAILING") ||
      TokenTextEquals(tokens, cursor, "BOTH")) {
    const std::string direction = ToUpperAscii(tokens[cursor]->text);
    if (direction == "LEADING") function_id = "sb.scalar.ltrim";
    if (direction == "TRAILING") function_id = "sb.scalar.rtrim";
    if (direction == "BOTH") function_id = "sb.special.trim_keyword";
    ++cursor;
  }

  std::optional<ScalarProjectionItem> trim_chars;
  if (!TokenTextEquals(tokens, cursor, "FROM")) {
    ScalarProjectionItem parsed_chars;
    if (!ParseScalarLiteralProjectionItem(tokens, &cursor, &parsed_chars)) return false;
    trim_chars = std::move(parsed_chars);
  }
  if (!ConsumeTokenText(tokens, &cursor, "FROM")) return false;
  ScalarProjectionItem source;
  if (!ParseScalarLiteralProjectionItem(tokens, &cursor, &source)) return false;
  if (!ConsumeTokenText(tokens, &cursor, ")")) return false;
  if (!NativeNowExpressionSurface("TRIM([LEADING\\|TRAILING\\|BOTH][chars]FROMtext)")) return false;
  if (function_id == "sb.scalar.ltrim" && !NativeNowExpressionSurface("ltrim(text[,chars])")) return false;
  if (function_id == "sb.scalar.rtrim" && !NativeNowExpressionSurface("rtrim(text[,chars])")) return false;
  if (function_id == "sb.special.trim_keyword" &&
      !NativeNowExpressionSurface("sb.special.trim_keyword")) {
    return false;
  }

  std::vector<ScalarProjectionItem> arguments;
  arguments.push_back(std::move(source));
  if (trim_chars) arguments.push_back(std::move(*trim_chars));

  item->expression_kind = "function";
  item->function_id = std::move(function_id);
  item->type_name = "character";
  item->is_null = false;
  item->arguments = std::move(arguments);
  *index = cursor;
  return true;
}

