AlterRenameDdlInfo AnalyzeAlterRenameDdl(
    const CstDocument& cst,
    const std::vector<std::string>& resolved_object_uuids) {
  AlterRenameDdlInfo info;
  std::size_t index = 0;
  if (ConsumeKeyword(cst, &index, "RENAME")) {
    info.active = true;
    info.standalone_rename = true;
  } else if (ConsumeKeyword(cst, &index, "ALTER")) {
    std::size_t probe = index;
    const std::string object_kind = ConsumeObjectClassName(cst, &probe);
    std::size_t name_parts = 0;
    if (object_kind.empty() || !ConsumeQualifiedName(cst, &probe, &name_parts) ||
        !ConsumeKeyword(cst, &probe, "RENAME")) {
      return info;
    }
    info.active = true;
    info.target_object_kind = object_kind;
    info.target_name_parts = name_parts;
    index = probe;
  } else {
    return info;
  }

  if (info.standalone_rename) {
    info.target_object_kind = ConsumeObjectClassName(cst, &index);
    if (info.target_object_kind.empty()) {
      info.invalid_reason = "rename_object_class_required";
      return info;
    }
    if (!ConsumeQualifiedName(cst, &index, &info.target_name_parts)) {
      info.invalid_reason = "rename_target_name_required";
      return info;
    }
  }
  if (info.target_object_kind == "cluster" || info.target_object_kind == "node") {
    info.invalid_reason = "rename_cluster_object_class_requires_cluster_provider";
    return info;
  }
  if (!ConsumeKeyword(cst, &index, "TO")) {
    info.invalid_reason = "rename_to_required";
    return info;
  }
  if (!ConsumeIdentifierText(cst, &index, &info.new_name)) {
    info.invalid_reason = "rename_new_name_required";
    return info;
  }
  if (!OnlyStatementTerminatorRemains(cst, index)) {
    info.invalid_reason = "rename_extra_tokens";
    return info;
  }
  if (resolved_object_uuids.empty()) {
    info.invalid_reason = "rename_target_uuid_required";
    return info;
  }
  info.target_object_uuid = resolved_object_uuids.front();
  if (resolved_object_uuids.size() > 1) info.target_schema_uuid = resolved_object_uuids[1];
  info.valid = true;
  return info;
}

