void PopulateDmlRouteAuthority(SblrEnvelope* envelope, const DmlRouteInfo& info) {
  if (!info.active || !info.valid) return;
  envelope->operation_id = info.operation_id;
  envelope->sblr_opcode = info.opcode;
  envelope->engine_api_operation_id = info.operation_id;
  if (!info.read) {
    envelope->operation_family = "sblr.dml.operation.v3";
    envelope->sblr_operation_key = "sblr.dml.operation.v3";
  }
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.syntax_evidence_only");
  if (info.requires_target_uuid) {
    AppendIfMissing(&envelope->required_authority_steps,
                    "authority.server.resolve_name_registry_public");
  }
  AppendIfMissing(&envelope->required_authority_steps,
                  "authority.server.security_policy_context_required");
  AppendIfMissing(&envelope->required_authority_steps,
                  "authority.server.transaction_context_required");
  AppendIfMissing(&envelope->required_authority_steps, "authority.engine.dml_api_required");
  if (info.import_planning) {
    AppendIfMissing(&envelope->required_authority_steps,
                    "authority.engine.import_planning_api_required");
  }
  AppendIfMissing(&envelope->required_authority_steps,
                  info.read ? "authority.engine.mga_snapshot_visibility_required"
                            : (info.import_planning
                                   ? "authority.engine.mga_import_planning_required"
                                   : "authority.engine.mga_row_mutation_required"));
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.no_security_authorization");
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.no_storage_or_finality");
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.no_sql_text_execution");
  AppendIfMissing(&envelope->descriptor_refs, "sys.catalog.object_descriptor");
  AppendIfMissing(&envelope->descriptor_refs, "sys.storage.row_descriptor");
  if (info.has_on_conflict) {
    AppendIfMissing(&envelope->descriptor_refs, "sys.storage.unique_index_descriptor");
    AppendIfMissing(&envelope->descriptor_refs, "sys.dml.conflict_policy_descriptor");
  }
  if (info.requires_target_uuid) {
    AppendIfMissing(&envelope->descriptor_refs, "sys.name_registry");
  }
  AppendIfMissing(&envelope->policy_refs, "dml_authorization_policy");
  AppendIfMissing(&envelope->policy_refs, info.read ? "row_visibility_policy"
                                                    : (info.import_planning
                                                           ? "import_planning_policy"
                                                           : "row_mutation_policy"));
  if (info.has_on_conflict) {
    AppendIfMissing(&envelope->policy_refs, "row_conflict_policy");
  }
}

void PopulateScalarProjectionAuthority(SblrEnvelope* envelope, const ScalarProjectionInfo& info) {
  if (!info.active || !info.valid) return;
  envelope->operation_id = "query.evaluate_projection";
  envelope->sblr_opcode = QueryOpcodeForOperation(envelope->operation_id);
  envelope->engine_api_operation_id = envelope->operation_id;
  envelope->operation_family = "sblr.query.relational.v3";
  envelope->sblr_operation_key = "sblr.query.relational.v3";
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.syntax_evidence_only");
  AppendIfMissing(&envelope->required_authority_steps, "authority.server.security_policy_context_required");
  AppendIfMissing(&envelope->required_authority_steps, "authority.server.transaction_context_required");
  AppendIfMissing(&envelope->required_authority_steps, "authority.engine.query_projection_api_required");
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.no_security_authorization");
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.no_storage_or_finality");
  AppendIfMissing(&envelope->required_authority_steps, "authority.parser.no_sql_text_execution");
  AppendIfMissing(&envelope->descriptor_refs, "sys.query.scalar_projection_descriptor");
  for (const auto& item : info.items) {
    if (item.expression_kind == "parameter") {
      AppendIfMissing(&envelope->descriptor_refs, "sys.query.parameter_descriptor");
      AppendIfMissing(&envelope->required_authority_steps,
                      "authority.server.bind_parameter_descriptors_required");
      break;
    }
  }
  AppendIfMissing(&envelope->policy_refs, "query_projection_authorization_policy");
}

