void AppendVectorSearchJson(std::ostream& out, const VectorSearchRouteInfo& info) {
  if (!info.active || !info.valid) return;
  out << "\"query_envelope_kind\":\"vector_search\","
      << "\"query_operation\":\"vector_search\","
      << "\"query_execute\":\"true\","
      << "\"vector_operation_id\":\"nosql.vector_search\","
      << "\"target_object_kind\":\"vector_collection\","
      << "\"target_object_uuid\":\"" << EscapeJson(info.target_object_uuid) << "\","
      << "\"target_name_parts\":" << info.target_name_parts << ','
      << "\"body_kind\":\""
      << (info.with_body ? "with_args" : (info.operator_body ? "distance_operator" : "unknown"))
      << "\","
      << "\"vector_value_descriptor\":\"dense_vector\","
      << "\"vector_value_embedded\":false,"
      << "\"metric\":\"" << EscapeJson(info.metric) << "\","
      << "\"filter_present\":" << (info.filter_present ? "true" : "false") << ','
      << "\"paging_present\":" << (info.paging_present ? "true" : "false") << ','
      << "\"rerank_present\":" << (info.rerank_present ? "true" : "false") << ','
      << "\"source_relation_required\":true,"
      << "\"row_storage_touched\":true,"
      << "\"mga_transaction_context_required\":true,"
      << "\"object_name_text_included\":false,"
      << "\"name_text_included\":false,"
      << "\"sql_text_included\":false,";
  if (!info.distance_operator.empty()) {
    out << "\"vector_distance_operator\":\"" << EscapeJson(info.distance_operator) << "\",";
  }
  if (!info.vector_modifier.empty()) {
    out << "\"vector_modifier\":\"" << EscapeJson(info.vector_modifier) << "\",";
  }
  if (!info.limit.empty()) out << "\"limit\":" << info.limit << ',';
  if (!info.offset.empty()) out << "\"offset\":" << info.offset << ',';
  if (!info.ef_search.empty()) out << "\"ef_search\":" << info.ef_search << ',';
  if (!info.nprobe.empty()) out << "\"nprobe\":" << info.nprobe << ',';
  if (!info.radius.empty()) out << "\"radius\":" << info.radius << ',';
  if (!info.paging_kind.empty()) {
    out << "\"paging_kind\":\"" << EscapeJson(info.paging_kind) << "\",";
  }
  if (!info.rerank_kind.empty()) {
    out << "\"rerank_kind\":\"" << EscapeJson(info.rerank_kind) << "\",";
  }
  out << "\"output_field_count\":" << info.output_field_count << ',';
  AppendJsonStringArray(out, "row_surface_ids", info.row_surface_ids);
  out << ',';
}

