void AppendPublicExactCommandJson(std::ostream& out,
                                const PublicExactCommandRouteInfo& info) {
  if (!info.active || !info.valid || info.spec == nullptr) return;
  const auto& spec = *info.spec;
  out << "\"public_sbsql_exact_command\":true,"
      << "\"surface_key\":\"" << EscapeJson(spec.surface_key) << "\","
      << "\"exact_syntax_included\":false,"
      << "\"normalized_syntax_included\":false,"
      << "\"exact_command_route_kind\":\"" << EscapeJson(spec.route_kind) << "\","
      << "\"operation_mutates_engine_state\":" << (spec.mutation ? "true" : "false") << ','
      << "\"canonical_sblr_operation\":\"" << EscapeJson(spec.operation_id) << "\","
      << "\"engine_api_function\":\"" << EscapeJson(spec.engine_api_function) << "\","
      << "\"engine_result_shape_contract\":\"" << EscapeJson(spec.result_shape) << "\","
      << "\"cluster_provider_dispatch\":"
      << (spec.requires_cluster_authority ? "true" : "false") << ','
      << "\"private_cluster_execution\":false,"
      << "\"private_error_vector_route\":false,"
      << "\"synthetic_replay\":false,"
      << "\"wal_recovery_authority\":false,"
      << "\"recovery_authority\":false,"
      << "\"source_relation_required\":false,"
      << "\"row_storage_touched\":false,"
      << "\"mga_finality_claimed\":false,"
      << "\"parser_authorizes\":false,"
      << "\"parser_executes_management_control\":false,"
      << "\"parser_executes_acceleration_control\":false,"
      << "\"parser_executes_security_inspection\":false,"
      << "\"name_text_included\":false,"
      << "\"sql_text_included\":false,";
  if (!info.target_ref.empty()) {
    out << "\"target_ref_kind\":\"" << EscapeJson(spec.target_kind) << "\","
        << "\"target_ref_descriptor\":\"engine_resolves_from_public_registry\","
        << "\"target_ref\":\"" << EscapeJson(info.target_ref) << "\",";
    if (spec.surface_key == "migrate.from_reference") {
      out << "\"reference_profile\":\"" << EscapeJson(info.target_ref) << "\",";
    } else if (spec.surface_key == "alter.migration" ||
               spec.surface_key == "show.migration") {
      out << "\"migration_ref\":\"" << EscapeJson(info.target_ref) << "\",";
    }
  }
  if (!info.count.empty()) {
    out << "\"resize_count\":\"" << EscapeJson(info.count) << "\",";
  }
  if (!info.secondary_ref.empty()) {
    out << "\"secondary_ref_kind\":\"" << EscapeJson(info.secondary_ref_kind) << "\","
        << "\"secondary_ref_descriptor\":\"engine_resolves_from_public_registry\","
        << "\"secondary_ref\":\"" << EscapeJson(info.secondary_ref) << "\",";
    if (spec.surface_key == "migrate.from_reference") {
      out << "\"reference_package\":\"" << EscapeJson(info.secondary_ref) << "\",";
    } else if (spec.surface_key == "alter.migration") {
      out << "\"migration_action\":\"" << EscapeJson(info.secondary_ref) << "\",";
    }
  }
}

