void AppendRowNumberWindowJson(std::ostream& out,
                               const RowNumberWindowInfo& info) {
  if (!info.active || !info.valid) return;
  const bool row_number = info.window_function == "row_number";
  const bool partition_count = info.window_function == "count_star_partition";
  const bool needs_value_field = info.window_function != "row_number" &&
                                 info.window_function != "count_star_partition" &&
                                 info.window_function != "rank" &&
                                 info.window_function != "dense_rank" &&
                                 info.window_function != "percent_rank" &&
                                 info.window_function != "cume_dist" &&
                                 info.window_function != "ntile";
  const bool typed_nullable_window = info.window_function == "percent_rank" ||
                                     info.window_function == "cume_dist" ||
                                     info.window_function == "nth_value";
  out << "\"query_envelope_kind\":\""
      << (partition_count ? "table_partition_count_window"
                          : (row_number ? "table_row_number_window" : "table_window"))
      << "\","
      << "\"query_operation\":\""
      << (partition_count ? "partition_count_window"
                          : (row_number ? "row_number_window" : "window"))
      << "\","
      << "\"query_execute\":\"true\","
      << "\"target_object_kind\":\"table\","
      << "\"target_object_uuid\":\"" << EscapeJson(info.object_uuid) << "\",";
  if (partition_count) {
    out << "\"partition_by\":\"" << EscapeJson(info.partition_field) << "\","
        << "\"partition_column\":\"0\","
        << "\"aggregate_function\":\"sb.aggregate.count\",";
  } else {
    out << "\"order_by\":\"" << EscapeJson(info.order_field) << "\","
        << "\"order_column\":\"0\",";
  }
  out
      << "\"window_function\":\"" << EscapeJson(info.window_function) << "\",";
  if (info.window_function == "ntile" || info.window_function == "nth_value") {
    out << "\"window_n\":\"" << info.window_n << "\",";
  }
  if (needs_value_field) {
    out << "\"window_value_field\":\"" << EscapeJson(info.value_field) << "\","
        << "\"window_value_column\":\"0\",";
  }
  if (info.named_window_reference) {
    out << "\"window_named_reference_present\":true,"
        << "\"window_name_ref_descriptor\":\"named_window_0\","
        << "\"window_name_text_included\":false,";
  }
  if (info.named_window_definition) {
    out << "\"window_named_definition_present\":true,"
        << "\"window_definition_descriptor\":\"named_window_0\",";
  }
  if (info.frame_clause) {
    out << "\"window_frame_clause_present\":true,"
        << "\"window_frame_mode\":\"" << EscapeJson(info.frame_mode) << "\","
        << "\"window_frame_start\":\"" << EscapeJson(info.frame_start) << "\","
        << "\"window_frame_end\":\"" << EscapeJson(info.frame_end) << "\",";
  }
  if (info.exclude_clause) {
    out << "\"window_exclude_clause_present\":true,"
        << "\"window_exclude_target\":\"" << EscapeJson(info.exclude_target) << "\",";
  }
  if (!info.grammar_surface_ids.empty()) {
    out << "\"window_grammar_surface_ids\":[";
    for (std::size_t surface_index = 0; surface_index < info.grammar_surface_ids.size();
         ++surface_index) {
      if (surface_index != 0) out << ',';
      out << "\"" << EscapeJson(info.grammar_surface_ids[surface_index]) << "\"";
    }
    out << "],";
  }
  out << "\"window_binding_model\":\""
      << (partition_count ? "engine_row_descriptor_field_int64_partition_count_route"
                          : (typed_nullable_window ? "engine_row_descriptor_field_typed_nullable_route"
                                                   : "engine_row_descriptor_field_int64_current_route"))
      << "\","
      << "\"source_relation_required\":true,"
      << "\"row_storage_touched\":true,"
      << "\"mga_transaction_context_required\":true,"
      << "\"object_name_text_included\":false,"
      << "\"sql_text_included\":false,";
}

void AppendGroupByAggregateJson(std::ostream& out,
                                const GroupByAggregateInfo& info) {
  if (!info.active || !info.valid) return;
  const bool sum_route = info.aggregate_function == "sb.aggregate.sum";
  const bool boolean_route = info.aggregate_function == "sb.aggregate.every" ||
                             info.aggregate_function == "sb.aggregate.bool_and" ||
                             info.aggregate_function == "sb.aggregate.bool_or";
  const bool int64_result_route =
      info.aggregate_function == "sb.aggregate.count" ||
      info.aggregate_function == "sb.aggregate.approx_count_distinct" ||
      info.aggregate_function == "sb.aggregate.regr_count";
  const bool numeric_result_route =
      info.aggregate_function == "sb.aggregate.avg" ||
      info.aggregate_function == "sb.aggregate.min" ||
      info.aggregate_function == "sb.aggregate.max";
  const bool json_result_route = info.aggregate_function == "sb.aggregate.approx_top_k" ||
                                 IsJsonAggAggregateFunctionId(info.aggregate_function) ||
                                 IsJsonObjectAggAggregateFunctionId(info.aggregate_function);
  const bool list_result_route = IsArrayAggAggregateFunctionId(info.aggregate_function);
  const bool text_result_route = IsOrderedTextAggregateFunctionId(info.aggregate_function);
  const bool ordered_json_result_route = IsJsonAggAggregateFunctionId(info.aggregate_function) ||
                                         IsJsonObjectAggAggregateFunctionId(info.aggregate_function);
  const bool ordered_list_result_route = IsArrayAggAggregateFunctionId(info.aggregate_function);
  const bool ordered_result_route = text_result_route || ordered_json_result_route ||
                                    ordered_list_result_route;
  const bool pair_route = IsPairAggregateFunctionId(info.aggregate_function) ||
                          IsJsonObjectAggAggregateFunctionId(info.aggregate_function);
  const std::string binding_model =
      sum_route
          ? "engine_row_descriptor_field_int64_current_route"
          : (boolean_route
                 ? "engine_row_descriptor_field_boolean_nullable_route"
                 : (int64_result_route
                        ? "engine_row_descriptor_field_int64_result_route"
                        : (numeric_result_route
                               ? "engine_row_descriptor_field_real64_nullable_route"
                               : (json_result_route
                                      ? "engine_row_descriptor_field_json_nullable_route"
                                      : (list_result_route
                                             ? "engine_row_descriptor_field_list_nullable_route"
                                             : (text_result_route
                                                    ? "engine_row_descriptor_field_text_nullable_route"
                                                    : "engine_row_descriptor_field_real64_nullable_route"))))));
  out << "\"query_envelope_kind\":\"" << (sum_route ? "table_group_sum" : "table_group_aggregate") << "\","
      << "\"query_operation\":\"group_by\","
      << "\"query_keyword_surface_ids\":[\"SBSQL-C287FF004431\""
      << (info.has_having ? ",\"SBSQL-91BFC12AD088\"" : "")
      << "],"
      << "\"query_execute\":\"true\","
      << "\"target_object_kind\":\"table\","
      << "\"target_object_uuid\":\"" << EscapeJson(info.object_uuid) << "\","
      << "\"group_key_field\":\"" << EscapeJson(info.group_field) << "\","
      << "\"aggregate_function\":\"" << EscapeJson(info.aggregate_function) << "\","
      << "\"aggregate_value_field\":\"" << EscapeJson(info.aggregate_field) << "\","
      << "\"group_key_column\":\"0\","
      << "\"aggregate_value_column\":\"1\","
      << "\"aggregate_binding_model\":\"" << binding_model << "\","
      << (ordered_result_route
              ? "\"order_by\":\"" + EscapeJson(info.order_field) + "\","
                "\"order_column\":\"0\","
              : "")
      << (text_result_route
              ? "\"listagg_separator\":\"" + EscapeJson(info.listagg_separator) + "\","
              : "")
      << (pair_route
              ? "\"aggregate_pair_value_field\":\"" + EscapeJson(info.aggregate_pair_field) + "\","
                "\"aggregate_pair_value_column\":\"2\","
              : "")
      << (info.has_having
              ? "\"having_predicate\":\"" + EscapeJson(info.having_predicate) + "\","
                "\"having_threshold\":\"" + EscapeJson(info.having_threshold) + "\","
                "\"having_aggregate_function\":\"" + EscapeJson(info.having_function) + "\","
                "\"having_value_field\":\"" + EscapeJson(info.having_value_field) + "\","
                "\"having_value_column\":\"1\","
                "\"having_group_key_field\":\"" + EscapeJson(info.group_field) + "\","
              : "")
      << (!info.aggregate_fraction.empty()
              ? "\"aggregate_fraction\":\"" + EscapeJson(info.aggregate_fraction) + "\","
              : "")
      << (!info.aggregate_limit.empty()
              ? "\"aggregate_limit\":\"" + EscapeJson(info.aggregate_limit) + "\","
              : "")
      << (!info.listagg_overflow_mode.empty()
              ? "\"listagg_overflow_mode\":\"" + EscapeJson(info.listagg_overflow_mode) + "\","
              : "")
      << (!info.listagg_max_output_bytes.empty()
              ? "\"listagg_max_output_bytes\":\"" + EscapeJson(info.listagg_max_output_bytes) + "\","
              : "")
      << (!info.listagg_truncation_indicator.empty()
              ? "\"listagg_truncation_indicator\":\"" + EscapeJson(info.listagg_truncation_indicator) + "\","
              : "")
      << (!info.listagg_with_count.empty()
              ? "\"listagg_with_count\":\"" + EscapeJson(info.listagg_with_count) + "\","
              : "")
      << "\"source_relation_required\":true,"
      << "\"row_storage_touched\":true,"
      << "\"mga_transaction_context_required\":true,"
      << "\"object_name_text_included\":false,"
      << "\"sql_text_included\":false,";
}

