void AppendMaterializedCteJson(std::ostream& out,
                               const MaterializedCteInfo& info) {
  if (!info.active || !info.valid) return;
  if (info.recursive) {
    out << "\"query_envelope_kind\":\"values_recursive_cte\","
        << "\"query_operation\":\"recursive_cte\","
        << "\"query_execute\":\"true\","
        << "\"cte_name_text_included\":false,"
        << "\"cte_strategy\":\"recursive_fixed_point_materialized\","
        << "\"cte_binding_model\":\"values_anchor_recursive_step_fixed_point_current_route\","
        << "\"recursive_iterations\":\"" << EscapeJson(info.recursive_iterations) << "\","
        << "\"relation_count\":\"2\","
        << "\"relation_0_row_count\":\"" << info.anchor_rows.size() << "\","
        << "\"relation_1_row_count\":\"" << info.recursive_rows.size() << "\","
        << "\"values_column_count\":\"" << info.column_count << "\","
        << "\"source_relation_required\":false,"
        << "\"row_storage_touched\":false,"
        << "\"mga_transaction_context_required\":true,"
        << "\"object_name_text_included\":false,"
        << "\"sql_text_included\":false,";
    const auto append_relation = [&](std::size_t relation,
                                     const std::vector<std::vector<ScalarProjectionItem>>& rows) {
      for (std::size_t row = 0; row < rows.size(); ++row) {
        for (std::size_t column = 0; column < rows[row].size(); ++column) {
          const auto& item = rows[row][column];
          out << "\"relation_" << relation << '_' << row << '_' << column
              << "_name\":\"" << EscapeJson(item.name) << "\","
              << "\"relation_" << relation << '_' << row << '_' << column
              << "_type\":\"" << EscapeJson(item.type_name) << "\","
              << "\"relation_" << relation << '_' << row << '_' << column
              << "_value\":\"" << EscapeJson(item.value) << "\","
              << "\"relation_" << relation << '_' << row << '_' << column
              << "_is_null\":\"" << (item.is_null ? "true" : "false") << "\",";
        }
      }
    };
    append_relation(0, info.anchor_rows);
    append_relation(1, info.recursive_rows);
    return;
  }
  out << "\"query_envelope_kind\":\"table_materialized_cte\","
      << "\"query_operation\":\"materialized_cte\","
      << "\"query_execute\":\"true\","
      << "\"target_object_kind\":\"table\","
      << "\"target_object_uuid\":\"" << EscapeJson(info.object_uuid) << "\","
      << "\"cte_strategy\":\"materialized\","
      << "\"cte_binding_model\":\"single_nonrecursive_cte_uuid_source_current_route\","
      << "\"source_relation_required\":true,"
      << "\"row_storage_touched\":true,"
      << "\"mga_transaction_context_required\":true,"
      << "\"object_name_text_included\":false,"
      << "\"sql_text_included\":false,";
}

